// ─────────────────────────────────────────────
// VHSYS :: employers_general_data
// Rota   : POST /employers_general_data
// Fase 4 : Fluxo EMPLOYERS
// ─────────────────────────────────────────────
// Input  : { data: { source: { itens: [{Matricula, Nome, Cargo, Status, ...}] } } }
// Output : { status: 'success', message: '...' } HTTP 201
// Banco  : UPDATE employersData status_funcionario + nome_cargo_funcionario
//          DELETE employersData onde matricula não está mais na API
// Chave  : matricula_funcionario
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data || !body.data.source || !body.data.source.itens) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required structure: data.source.itens' }
  };
}

const itens = body.data.source.itens;

if (!Array.isArray(itens) || itens.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'itens must be a non-empty array' }
  };
}

// Lista de matrículas da API (para DELETE dos demitidos)
const matriculas = itens
  .map(i => String(i.Matricula || '').trim())
  .filter(m => m !== '');

console.log(JSON.stringify({
  timestamp : new Date().toISOString(),
  route     : 'employers_general_data',
  event     : 'input_validated',
  count     : itens.length,
  level     : 'info'
}));

return { _valid: true, itens, matriculas };

// Expande cada item para um registro separado preservando lista de matrículas
const ctx = $input.first().json;
return ctx.itens.map(item => ({
  matricula  : String(item.Matricula || '').trim(),
  status     : String(item.Status    || '').trim(),
  cargo      : String(item.Cargo     || '').trim(),
  matriculas : ctx.matriculas
}));

// Recupera lista de matrículas do primeiro item
// (todos os itens carregam a mesma lista)
const allItems = $input.all();
const first = allItems.find(i => i.json.matriculas);
const matriculas = first ? first.json.matriculas : [];

console.log(JSON.stringify({
  timestamp  : new Date().toISOString(),
  route      : 'employers_general_data',
  event      : 'updates_done_preparing_cleanup',
  matriculas_count: matriculas.length,
  level      : 'info'
}));

return { matriculas };

