-- Delete employers que existem no banco mas não estão mais na API (demitidos)
DELETE FROM "auxiliary.employersData"
WHERE matricula_funcionario NOT IN (
  SELECT unnest($1::text[])
)
RETURNING matricula_funcionario, nome_funcionario;

